module RefModule(
    input [7:0]A,
    input [7:0]B,
    output [7:0] Sum,
    output Overflow
    );reg[8:0] tempSum;
  wire [7:0] _tap_A = A & {8{1'b1}};

	reg tempOv;

	always @(A or B)
	  begin
		 tempSum = A + B;
		 tempOv = tempSum[8];
	  end

  assign Sum = tempSum;
  assign Overflow = tempOv;




endmodule
